void main() {
  const policy = RendererBackendPolicy();

  // Helper to build a standard 2D auto input with overrides.
  BackendPolicyInput buildInput({
    bool isAndroid = false,
    bool isWeb = false,
    bool isEmulator = false,
    RendererBackendMode userMode = RendererBackendMode.auto,
    bool gpuHealthFailed = false,
    bool deepZoomNeedsCpu = false,
    FractalDimension dimension = FractalDimension.twoD,
  }) {
    return BackendPolicyInput(
      isAndroid: isAndroid,
      isWeb: isWeb,
      isEmulator: isEmulator,
      userMode: userMode,
      gpuHealthFailed: gpuHealthFailed,
      deepZoomNeedsCpu: deepZoomNeedsCpu,
      dimension: dimension,
    );
  }

  group('cpuOnly user mode', () {
    test('cpuOnly always returns cpu backend for 2D', () {
      final decision = policy.decide(buildInput(userMode: RendererBackendMode.cpuOnly));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly on non-emulator non-android still returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: false,
        isEmulator: false,
        userMode: RendererBackendMode.cpuOnly,
      ));
      expect(decision.backend, RendererBackend.cpu);
    });

    test('cpuOnly with gpuHealthFailed still returns cpu via manualToggle', () {
      // cpuOnly is evaluated before health-check; reason should be manualToggle
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly is ignored for 3D module — GPU required', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // 3D always uses GPU; cpuOnly is overridden
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
    });
  });

  group('gpuOnly user mode', () {
    test('gpuOnly always returns gpu backend for 2D', () {
      final decision = policy.decide(buildInput(userMode: RendererBackendMode.gpuOnly));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses deep-zoom CPU fallback', () {
      // gpuOnly is evaluated before deepZoomNeedsCpu check
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses GPU health check', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });
  });

  group('deep zoom CPU fallback', () {
    test('deepZoomNeedsCpu triggers cpu backend in auto mode', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.deepZoomPrecision);
    });

    test('deepZoomNeedsCpu reasonToken is deep_zoom_precision', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.reasonToken, 'deep_zoom_precision');
    });

    test('deepZoomNeedsCpu is evaluated after gpuHealthFailed', () {
      // gpuHealthFailed is checked first in the policy
      final decision = policy.decide(buildInput(
        gpuHealthFailed: true,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });
  });

  group('GPU health failure', () {
    test('GPU health failure in auto mode returns cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('combined emulator + GPU health fail returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: true,
        isEmulator: true,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('isFallback is true when backend is cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.isFallback, isTrue);
    });
  });

  group('healthy GPU with auto mode', () {
    test('healthy GPU with auto mode returns gpu', () {
      final decision = policy.decide(buildInput());
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('isFallback is false for gpu decision', () {
      final decision = policy.decide(buildInput());
      expect(decision.isFallback, isFalse);
    });

    test('reasonToken is none for healthy GPU', () {
      final decision = policy.decide(buildInput());
      expect(decision.reasonToken, 'none');
    });

    test('toUserStatusText returns GPU label on healthy path', () {
      final decision = policy.decide(buildInput());
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('3D module (unsupported GPU override)', () {
    test('3D module with auto mode uses GPU', () {
      final decision = policy.decide(buildInput(dimension: FractalDimension.threeD));
      expect(decision.backend, RendererBackend.gpu);
    });

    test('cpuOnly is ignored for 3D — moduleUnsupported reason', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
      expect(decision.reasonToken, 'module_unsupported');
    });

    test('3D module toUserStatusText returns GPU label (backend is gpu)', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // backend == gpu so isFallback is false; toUserStatusText returns 'Renderer: GPU'
      // regardless of reasonCode because the !isFallback check fires first.
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.isFallback, isFalse);
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('BackendDecision helpers', () {
    test('toLogLine contains backend, reason, module, and detail', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: 'deep_zoom_precision_policy',
      );
      final line = decision.toLogLine(moduleId: 'mandelbrot');
      expect(line, contains('backend=cpu'));
      expect(line, contains('reason=deep_zoom_precision'));
      expect(line, contains('module=mandelbrot'));
      expect(line, contains('detail=deep_zoom_precision_policy'));
    });

    test('toUserStatusText for deep zoom precision', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: '',
      );
      expect(decision.toUserStatusText(), 'Deep zoom precision mode enabled');
    });

    test('toUserStatusText for manual toggle cpu', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.manualToggle,
        detail: 'cpu_only',
      );
      expect(decision.toUserStatusText(), 'Renderer preference applied');
    });

    test('toUserStatusText for forced by flag', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.forcedByFlag,
        detail: '',
      );
      expect(decision.toUserStatusText(), 'Stable renderer forced by launch flag');
    });
  });
}

import 'dart:math' as math;
import 'dart:typed_data';

const int _rgbaStride = 4;

/// Numeric thresholds used by render-health probes.
///
/// Keeping these cutoffs in one value object makes the pass/fail contract
/// replayable from tests instead of scattering magic constants through the
/// frame and pair validators.
class RenderValidationThresholds {
  final int blackThreshold;
  final int differenceThreshold;
  final double minimumNonBlackRatio;
  final double minimumProgressionRatio;
  final double minimumIterationDeltaRatio;

  static const defaults = RenderValidationThresholds();

  const RenderValidationThresholds({
    this.blackThreshold = 8,
    this.differenceThreshold = 12,
    this.minimumNonBlackRatio = 0.01,
    this.minimumProgressionRatio = 0.002,
    this.minimumIterationDeltaRatio = 0.01,
  })  : assert(blackThreshold >= 0),
        assert(differenceThreshold >= 0),
        assert(minimumNonBlackRatio >= 0.0),
        assert(minimumProgressionRatio >= 0.0),
        assert(minimumIterationDeltaRatio >= 0.0);

  bool isNonBlackPixel(int r, int g, int b) =>
      r > blackThreshold || g > blackThreshold || b > blackThreshold;

  bool isVisiblyDifferent({
    required int rA,
    required int gA,
    required int bA,
    required int rB,
    required int gB,
    required int bB,
  }) {
    final dr = (rB - rA).abs();
    final dg = (gB - gA).abs();
    final db = (bB - bA).abs();
    return dr + dg + db > differenceThreshold;
  }

  bool histogramSaneFor(double nonBlackRatio) =>
      nonBlackRatio > minimumNonBlackRatio;

  bool frameProgressedFor(double progressionRatio) =>
      progressionRatio > minimumProgressionRatio;

  bool iterationDeltaVisibleFor(double progressionRatio) =>
      progressionRatio > minimumIterationDeltaRatio;
}

class _RenderFrameGeometry {
  final int width;
  final int height;
  final int totalPixels;
  final int centerIndex;

  const _RenderFrameGeometry._({
    required this.width,
    required this.height,
    required this.totalPixels,
    required this.centerIndex,
  });

  factory _RenderFrameGeometry({required int width, required int height}) {
    if (width <= 0 || height <= 0) {
      return _RenderFrameGeometry._(
        width: width,
        height: height,
        totalPixels: 0,
        centerIndex: -1,
      );
    }

    final totalPixels = width * height;
    final cx = (width / 2).floor();
    final cy = (height / 2).floor();
    return _RenderFrameGeometry._(
      width: width,
      height: height,
      totalPixels: totalPixels,
      centerIndex: (cy * width + cx) * _rgbaStride,
    );
  }

  bool canReadCenter(Uint8List frame) =>
      centerIndex >= 0 && centerIndex + 2 < frame.length;

  int readablePixelCount(Uint8List frame) =>
      math.min(totalPixels, frame.length ~/ _rgbaStride);

  bool hasCompleteFrame(Uint8List frame) =>
      totalPixels > 0 && readablePixelCount(frame) == totalPixels;
}

bool _isNonBlack(Uint8List frame, int index) =>
    RenderValidationThresholds.defaults.isNonBlackPixel(
      frame[index],
      frame[index + 1],
      frame[index + 2],
    );

bool _isVisiblyDifferent(Uint8List frameA, Uint8List frameB, int index) =>
    RenderValidationThresholds.defaults.isVisiblyDifferent(
      rA: frameA[index],
      gA: frameA[index + 1],
      bA: frameA[index + 2],
      rB: frameB[index],
      gB: frameB[index + 1],
      bB: frameB[index + 2],
    );

int _countNonBlackPixels(Uint8List frame, int readablePixels) {
  int nonBlack = 0;
  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isNonBlack(frame, i)) {
      nonBlack++;
    }
  }
  return nonBlack;
}

int _countDifferentPixels({
  required Uint8List frameA,
  required Uint8List frameB,
  required int readablePixels,
}) {
  int different = 0;
  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isVisiblyDifferent(frameA, frameB, i)) {
      different++;
    }
  }
  return different;
}

class RenderFrameStats {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;

  const RenderFrameStats({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
  });

  String summary(String backend) {
    return '[renderer] render_frame_stats backend=$backend center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} histogram_sane=$histogramSane';
  }
}

RenderFrameStats validateRenderFrame({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final cIndex = geometry.centerIndex;
  final centerR = geometry.canReadCenter(frame) ? frame[cIndex] : 0;
  final centerG = geometry.canReadCenter(frame) ? frame[cIndex + 1] : 0;
  final centerB = geometry.canReadCenter(frame) ? frame[cIndex + 2] : 0;

  final centerNonBlack =
      geometry.canReadCenter(frame) && _isNonBlack(frame, cIndex);

  final readablePixels = geometry.readablePixelCount(frame);
  final nonBlack = _countNonBlackPixels(frame, readablePixels);

  final nonBlackRatio =
      geometry.totalPixels == 0 ? 0.0 : nonBlack / geometry.totalPixels;
  final histogramSane =
      RenderValidationThresholds.defaults.histogramSaneFor(nonBlackRatio);

  return RenderFrameStats(
    centerR: centerR,
    centerG: centerG,
    centerB: centerB,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: centerNonBlack,
    histogramSane: histogramSane,
  );
}

class RenderCheckResult {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;
  final bool frameProgressed;
  final bool iterationDeltaVisible;

  const RenderCheckResult({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
    required this.frameProgressed,
    required this.iterationDeltaVisible,
  });

  bool get pass =>
      centerNonBlack &&
      histogramSane &&
      frameProgressed &&
      iterationDeltaVisible;

  String summary(String backend) {
    return '[renderer] render_check backend=$backend pass=$pass center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} frame_progressed=$frameProgressed iter_delta=$iterationDeltaVisible';
  }
}

RenderCheckResult validateRenderPair({
  required Uint8List frameA,
  required Uint8List frameB,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final cIndex = geometry.centerIndex;
  final centerR = geometry.canReadCenter(frameB) ? frameB[cIndex] : 0;
  final centerG = geometry.canReadCenter(frameB) ? frameB[cIndex + 1] : 0;
  final centerB = geometry.canReadCenter(frameB) ? frameB[cIndex + 2] : 0;

  final centerNonBlack =
      geometry.canReadCenter(frameB) && _isNonBlack(frameB, cIndex);

  final frameBReadablePixels = geometry.readablePixelCount(frameB);
  final comparablePixels = math.min(
    geometry.readablePixelCount(frameA),
    frameBReadablePixels,
  );
  final nonBlack = _countNonBlackPixels(frameB, frameBReadablePixels);
  final different = _countDifferentPixels(
    frameA: frameA,
    frameB: frameB,
    readablePixels: comparablePixels,
  );
  final hasCompletePair =
      geometry.hasCompleteFrame(frameA) && geometry.hasCompleteFrame(frameB);

  final nonBlackRatio =
      geometry.totalPixels == 0 ? 0.0 : nonBlack / geometry.totalPixels;
  final histogramSane =
      RenderValidationThresholds.defaults.histogramSaneFor(nonBlackRatio);
  // Progression is a whole-frame claim; a truncated frame can still prove the
  // current histogram, but cannot prove frame-to-frame movement.
  final progressionRatio = geometry.totalPixels == 0 || !hasCompletePair
      ? 0.0
      : different / geometry.totalPixels;
  final frameProgressed =
      RenderValidationThresholds.defaults.frameProgressedFor(progressionRatio);
  final iterationDeltaVisible = RenderValidationThresholds.defaults
      .iterationDeltaVisibleFor(progressionRatio);

  return RenderCheckResult(
    centerR: centerR,
    centerG: centerG,
    centerB: centerB,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: centerNonBlack,
    histogramSane: histogramSane,
    frameProgressed: frameProgressed,
    iterationDeltaVisible: iterationDeltaVisible,
  );
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';

/// Catalog data source for the Explore screen.
///
/// Phase 1: derives entries from currently implemented modules while assigning
/// stable catalog IDs. This keeps IDs future-proof for PRD-200 ingest.
class CatalogRepository {
  final List<CatalogEntry> entries;

  const CatalogRepository({required this.entries});

  factory CatalogRepository.fromRegistry(ModuleRegistry registry) {
    final categoriesById = {
      for (final config in escapeTimeCatalog) config.id: config.category,
      for (final config in raymarched3DCatalog) config.id: config.category,
    };

    return CatalogRepository(
      entries: registry.modules
          .map(
            (module) => CatalogEntry(
              // Stable prefix to decouple future module refactors from IDs.
              catalogId: 'core.${module.id}',
              module: module,
              category: categoriesById[module.id] ??
                  (module.dimension == FractalDimension.threeD
                      ? '3D Fractals'
                      : 'Other'),
            ),
          )
          .toList(growable: false),
    );
  }

  CatalogEntry byCatalogId(String catalogId) {
    return entries.firstWhere((entry) => entry.catalogId == catalogId);
  }

  @visibleForTesting
  Set<String> allIds() => entries.map((e) => e.catalogId).toSet();
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/catalog/catalog_repository.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CatalogRepository', () {
    test('creates stable prefixed IDs from module registry', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.entries, isNotEmpty);
      expect(repo.entries.length, registry.modules.length);
      expect(repo.entries.first.catalogId, startsWith('core.'));
      expect(repo.byCatalogId('core.mandelbrot').module.id, 'mandelbrot');
    });

    test('catalog IDs are unique', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.allIds().length, repo.entries.length);
    });

    test('keeps intended 3D runtime modules for implemented 3D catalog ids', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(
        repo.byCatalogId('core.quaternion_julia_3d').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.dual_quaternion_julia').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.mandelbox_shape_inversion').module.dimension,
        FractalDimension.threeD,
      );
    });
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time_catalog.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time_builder.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';

/// Catalog ID integrity tests (P0 #4).
///
/// These tests act as a lock on the catalog — any accidental rename,
/// removal, or duplication of a catalog ID will be caught here.
///
/// ## Expected counts (update when catalog intentionally grows)
///
/// - Escape-time catalog unique top-level IDs : 490
/// - Raymarched-3D catalog unique IDs         :   9
/// - Custom hand-built modules                :   6
///   (julia, julia_dual, phoenix, nova, mandelbulb, mandelbox)
/// - Total ModuleRegistry modules (non-debug) : 505
///
/// The "196 GPU shaders" figure in TODO.md refers to fragment shader
/// assets compiled at build time; it predates the full catalog expansion.
void main() {
  // ---------------------------------------------------------------------------
  // 1. Escape-time catalog — raw entries
  // ---------------------------------------------------------------------------
  group('EscapeTimeConfig catalog entries', () {
    late final List<EscapeTimeConfig> catalog;

    setUpAll(() {
      catalog = escapeTimeCatalog;
    });

    test('total entry count is 491 (including 1 known duplicate)', () {
      expect(catalog.length, 491,
          reason: 'Update this constant when new entries are intentionally '
              'added to escape_time_catalog.dart.');
    });

    test('all IDs match pattern: lowercase alphanumeric + underscores', () {
      final pattern = RegExp(r'^[a-z0-9_]+$');
      final bad = catalog
          .map((c) => c.id)
          .where((id) => !pattern.hasMatch(id))
          .toList();
      expect(bad, isEmpty,
          reason: 'IDs must be lowercase alphanumeric + underscores. '
              'Bad IDs: $bad');
    });

    test('no catalog entry has an empty name', () {
      final empty = catalog.where((c) => c.name.trim().isEmpty).toList();
      expect(empty.map((c) => c.id).toList(), isEmpty,
          reason: 'Every catalog entry must have a non-empty name.');
    });

    test('no catalog entry has an empty shader asset path', () {
      final empty = catalog.where((c) => c.shaderAsset.trim().isEmpty).toList();
      expect(empty.map((c) => c.id).toList(), isEmpty,
          reason: 'Every catalog entry must declare a shaderAsset path.');
    });

    // Snapshot test: any rename/removal/addition will fail here.
    // Update this list when intentionally changing catalog IDs.
    test('snapshot — first 20 catalog IDs are stable', () {
      final expected = [
        'mandelbrot',
        'burning_ship',
        'tricorn',
        'celtic',
        'buffalo',
        'multibrot3',
        'nova_julia',
        'fatou',
        'gamma_fractal',
        'perpendicular_mandelbrot',
        'lambda',
        'magnet_type_1',
        'magnet_type_2',
        'magnet_type_3',
        'power_sum',
        'cactus',
        'astroid',
        'deltoid',
        'eisenstein',
        'druid',
      ];
      final actual = catalog.take(20).map((c) => c.id).toList();
      expect(actual, expected,
          reason: 'First-20 catalog IDs changed. '
              'If intentional, update this snapshot.');
    });
  });

  // ---------------------------------------------------------------------------
  // 2. ModuleRegistry — built registry (release mode, no debug modules)
  // ---------------------------------------------------------------------------
  group('ModuleRegistry integrity', () {
    late final ModuleRegistry registry;

    setUpAll(() {
      registry = ModuleRegistry();
    });

    test('total module count is 505 (non-debug)', () {
      // Debug-only diagnostic modules are excluded in release/test builds
      // because kDebugMode is false in test environments.
      expect(registry.modules.length, 505,
          reason: 'Update this constant when new modules are intentionally '
              'added. Current breakdown: 355 escape-time + 9 raymarched-3D '
              '+ 6 custom = 370.');
    });

    test('all module IDs are unique (no duplicates)', () {
      final ids = registry.modules.map((m) => m.id).toList();
      final seen = <String>{};
      final dupes = <String>[];
      for (final id in ids) {
        if (!seen.add(id)) dupes.add(id);
      }
      expect(dupes, isEmpty,
          reason: 'Duplicate module IDs detected: $dupes. '
              'The registry deduplicates, but duplicates in the raw catalog '
              'waste entries.');
    });

    test('all module IDs match pattern: lowercase alphanumeric + underscores',
        () {
      final pattern = RegExp(r'^[a-z0-9_]+$');
      final bad = registry.modules
          .map((m) => m.id)
          .where((id) => !pattern.hasMatch(id))
          .toList();
      expect(bad, isEmpty, reason: 'Non-conforming module IDs: $bad');
    });

    test('no module has an empty shader asset path', () {
      final empty = registry.modules
          .where((m) => m.shaderAsset.trim().isEmpty)
          .map((m) => m.id)
          .toList();
      expect(empty, isEmpty,
          reason: 'Every module must declare a non-empty shaderAsset. '
              'Missing: $empty');
    });

    test('byId lookup succeeds for mandelbrot', () {
      expect(() => registry.byId('mandelbrot'), returnsNormally);
      expect(registry.byId('mandelbrot').id, 'mandelbrot');
    });

    test('byId lookup succeeds for all custom hand-built modules', () {
      const customIds = [
        'julia',
        'julia_dual',
        'phoenix',
        'nova',
        'mandelbulb',
        'mandelbox',
      ];
      for (final id in customIds) {
        expect(
          () => registry.byId(id),
          returnsNormally,
          reason: 'Custom module "$id" not found in registry.',
        );
      }
    });

    // Snapshot of known-stable IDs. Removing or renaming any of these will
    // fail this test, prompting an intentional update.
    test('snapshot — known stable module IDs are present', () {
      const knownIds = [
        'mandelbrot',
        'julia',
        'julia_dual',
        'burning_ship',
        'phoenix',
        'nova',
        'nova_julia',
        'tricorn',
        'celtic',
        'buffalo',
        'multibrot3',
        'mandelbulb',
        'mandelbox',
        'kifs_menger',
        'kifs_sierpinski_tetra',
        'quaternion_julia_3d',
      ];
      final registryIds = registry.modules.map((m) => m.id).toSet();
      final missing = knownIds.where((id) => !registryIds.contains(id));
      expect(missing, isEmpty,
          reason: 'Previously-present module IDs are missing: $missing. '
              'If intentional, update this snapshot.');
    });
  });
}

